+            const error = `Circular agent delegation detected: ${[...path, delegatedAgentId].join(" -> ")}`;
+            yield { type: "error", error };
+            delegated = { content: error, isError: true };
+          } else if (!instructions) {
+            delegated = { content: "delegate_task requires instructions.", isError: true };
+          } else {
